// 1. 初始化
int n = nums.length;
int[] res = new int[n];
Arrays.fill(res, 0);
Deque&lt;Integer&gt; stack = new ArrayDeque&lt;&gt;();

// 2. 遍历数组
for (int i = 0; i &lt; n; i++) {
    while (!stack.isEmpty() && nums[i] > nums[stack.peek()]) {
        int idx = stack.pop();
        res[idx] = i - idx;
    }
    stack.push(i);
}

// 3. 返回 res
// ⚠️ 栈里剩下的 → 保持默认值 0


  👋 点击 下一步 开始，看模板每一行怎么执行

  输入数组 nums



  栈（存下标，栈顶在右）
  空栈

  结果数组 res



    当前 i
    在栈中
    被弹出
    已结算



    🔄 重置
    ▶ 下一步
    ⏩ 自动


    速度

    800ms




(function(){
const N=[73,74,75,71,69,72,76,73],n=N.length;
const codeLines=[
  '// 1. 初始化',
  'int n = nums.length;',
  'int[] res = new int[n];',
  'Arrays.fill(res, 0);',
  'Deque stack = new ArrayDeque();',
  '',
  '// 2. 遍历数组',
  'for (int i = 0; i < n; i++) {',
  '    while (!stack.isEmpty() && nums[i] > nums[stack.peek()]) {',
  '        int idx = stack.pop();',
  '        res[idx] = i - idx;',
  '    }',
  '    stack.push(i);',
  '}',
  '',
  '// 3. 返回 res',
  '// ⚠️ 栈里剩下的 → 保持默认值 0'
];

function mkSteps(){
  const S=[],sk=[],res=Array(n).fill(0),se=new Set(),ins=new Set();
  function snap(t,i,p,m,hl){S.push({t,i,sk:[...sk],res:[...res],se:new Set(se),ins:new Set(ins),p,m,hl})}
  snap('init',-1,-1,'初始化：res 全填 0，栈为空',[0,1,2,3,4]);
  for(let i=0;iN[top]?'>':'≤'} nums[${top}]=${N[top]}`)
    ,[7,8]);
    while(sk.length>0 && N[i]>N[sk[sk.length-1]]){
      const idx=sk.pop();ins.delete(idx);
      res[idx]=i-idx;se.add(idx);
      const more=sk.length>0&&N[i]>N[sk[sk.length-1]];
      snap('pop',i,idx,
        `弹出 ${idx}：${N[i]} > ${N[idx]} → res[${idx}] = ${i}-${idx} = ${i-idx}`+
        `👉 谁被弹出，谁结算！`+
        (more?`继续比较 ${N[i]} > nums[${sk[sk.length-1]}]=${N[sk[sk.length-1]]}`:'')
      ,[8,9,10]);
    }
    sk.push(i);ins.add(i);
    snap('push',i,-1,
      `压入 ${i}（值${N[i]}）→ 栈：[${sk.map(s=>s+'('+N[s]+')').join(', ')}]`
    ,[12]);
  }
  const rem=[...sk];
  snap('done',n,-1,
    '✅ 遍历完成！'+
    (rem.length?`⚠️ 栈剩 [${rem.map(s=>s+'('+N[s]+')').join(',')}] → 保持默认值 0`:'')+
    `结果 res = [${res.join(', ')}]`
  ,[15,16]);
  return S;
}

let steps=mkSteps(),cur=0,timer=null;

function initUI(){
  const a=document.getElementById('msArr'),p=document.getElementById('msPtr'),r=document.getElementById('msRes');
  a.innerHTML='';p.innerHTML='';r.innerHTML='';
  for(let i=0;i{
    const esc=l.replace(//g,'&gt;');
    return hlLines&&hlLines.includes(i)?`${esc}`:esc;
  }).join('\n');
}

function render(s){
  document.getElementById('msNarr').innerHTML=s.m;
  document.getElementById('msProg').style.width=((cur/(steps.length-1))*100)+'%';
  for(let i=0;i`${N[i]}i=${i}`).join('');
  for(let i=0;i=steps.length-1;
}

window.msNextStep=function(){if(cur>=steps.length-1)return;cur++;render(steps[cur])};
window.msReset=function(){msStop();cur=0;initUI();render(steps[0])};
window.msToggle=function(){timer?msStop():msStart()};
function msStart(){
  document.getElementById('msAuto').textContent='⏸ 暂停';
  const sp=parseInt(document.getElementById('msSpd').value);
  timer=setInterval(()=>{if(cur>=steps.length-1){msStop();return}msNextStep()},sp);
}
function msStop(){clearInterval(timer);timer=null;document.getElementById('msAuto').textContent='⏩ 自动'}
document.getElementById('msSpd').addEventListener('input',function(){
  document.getElementById('msSpdL').textContent=this.value+'ms';
  if(timer){msStop();msStart()}
});
initUI();render(steps[0]);
})();




🔑 核心要点
栈里存什么？

下标 index，不是值。目的不是排序，而是”填答案数组”。

答案容器怎么选？

👉 答案跟下标走 → 数组👉 答案跟值走 → 哈希表

While 条件怎么判断？

👉 找更大 → while nums[i] &gt; nums[top]👉 找更小 → while nums[i] &lt; nums[top]

方向怎么定？

👉 找右边 → 从左往右遍历👉 找左边 → 从右往左遍历

栈里剩余元素？

⚠️ 遍历结束后栈里还有元素 → 没找到答案，保持默认值



📝 练习题1. LeetCode 739. 每日温度题意： 给定每天温度数组，求每天要等几天才能遇到更高温度，没有则为 0。

🏷️ 这题 &#x3D; 单调栈「找右边第一个更大元素」👉 关键：res[idx] = i - idx（温度差 &#x3D; 当前下标 - 栈顶下标）


2. LeetCode 496. 下一个更大元素 I题意： nums1 是 nums2 的子集，对 nums1 每个元素找它在 nums2 中右侧第一个更大的值，没有返回 -1。

🏷️ 这题 &#x3D; 单调栈 + 哈希表映射👉 关键：先对 nums2 建「值 → 下一个更大值」的 map，再用 nums1 查表


3. LeetCode 503. 下一个更大元素 II题意： 循环数组，找每个元素的下一个更大元素，不存在返回 -1。

🏷️ 这题 &#x3D; 单调栈 + 循环数组👉 关键：遍历 2*n，下标用 i % n（循环 &#x3D; 遍历两遍 + 取模）

🧠 要求保持相对顺序原地修改,且要”删除&#x2F;筛选&#x2F;移动”元素 一句话结论：👉 四个问题:结构变不变(判断是否适用),什么情况可以保留,slow,fast快慢指针的核心不在于“删除”，而在于**“保留”**。 思路逆转：不要管哪些元素要删掉，只关心 “哪些元素应该被保留”，并把它们按照顺序用 slow 指针重组在数组的前缀区。 返回值意义：slow 的值定义了“有效区间 [0, slow)”，区间之外的数据在算法语义上等同于“不存在”，无需物理删除。
⭐ 模板 slow：始终指向“下一个合法元素应该放置的位置”int slow &#x3D; 0;
fast：遍历整个数组for (int fast &#x3D; 0; fast &lt; nums.length; fast++) {&#x2F;&#x2F; 核心判断：当前 fast 指向的元素，是我们需要保留的吗if ( 满足保留条件 ) {nums[slow] &#x3D; nums[fast];slow++;}}
slow 的值正好就是新数组的长度return slow;
Questions ① 结构变不变？
❌ 不新建数组 ✅ 通常要求保持剩余元素的「相对顺序」 ✅ 原地修改 👉 满足 ⇒ 快慢指针
② 什么情况下「可以保留」？
👉 哪些元素，应该被放到数组前面？
③ slow 是谁？
slow 永远表示：下一个“合法元素”应该放的位置
相关练习题1. LeetCode 27. 移除元素题意： 给你一个数组 nums 和一个值 val，你需要 原地 移除所有数值等于 val 的元素。元素的顺序可能发生改变。然后返回 nums 中与 val 不同的元素的数量。 2. LeetCode 26. 删除有序数组中的重复项题意： 给你一个 非严格递增排列 的数组 nums ，请你 原地 删除重复出现的元素，使每个元素 只出现一次 ，返回删除后数组的新长度。元素的 相对顺序 应该保持 一致 。然后返回 nums 中唯一元素的个数。 3. LeetCode 80. 删除有序数组中的重复项 II题意： 给你一个有序数组 nums ，请你 原地 删除重复出现的元素，使得出现次数超过两次的元素只出现两次 ，返回删除后数组的新长度。 Tips:通用去重模板（保留 k 位）：if (slow &lt; k || nums[fast] != nums[slow - k]) &#123;nums[slow] = nums[fast];slow++;&#125;

🧠 枚举回文中心，用左右指针向两边扩散，专治一切回文相关问题。
🧩 模板步骤
枚举中心位置 i
以 (i, i) 作为中心（奇数回文）
以 (i, i + 1) 作为中心（偶数回文）
左右指针同时扩散：left–、right++
越界或不相等立即停止



⭐ 模板
中心扩散函数
&#x2F;&#x2F; 从中心 left, right 开始向两边扩散private int expand(String s, int left, int right) {while (left &gt;&#x3D; 0 &amp;&amp; right &lt; s.length() &amp;&amp; s.charAt(left) &#x3D;&#x3D; s.charAt(right)) {left–;right++;}
&#x2F;&#x2F; 返回当前回文长度return right - left - 1;}

主流程模板
int n &#x3D; s.length();int maxLen &#x3D; 0;
for (int i &#x3D; 0; i &lt; n; i++) {int len1 &#x3D; expand(s, i, i); &#x2F;&#x2F; 奇数回文int len2 &#x3D; expand(s, i, i + 1); &#x2F;&#x2F; 偶数回文MaxLen &#x3D; Math.max(maxLen, Math.max(len1, len2));}




Notice:

while 条件顺序不能乱


正确顺序：先判边界，再比字符
while (left &gt;&#x3D; 0 &amp;&amp; right &lt; n &amp;&amp; s.charAt(left) &#x3D;&#x3D; s.charAt(right))
❌ 错误写法（可能越界）：
s.charAt(left) &#x3D;&#x3D; s.charAt(right) &amp;&amp; left &gt;&#x3D; 0


注意空串 &amp; 单字符


if (s &#x3D;&#x3D; null || s.length() &lt; 2) return s;


固定数据


回文子串的起始下标: start &#x3D; i - (len - 1) &#x2F; 2;
回文子串的结束下标: end &#x3D; i + len &#x2F; 2;
当前中心能扩散得到的「回文长度」: right - left - 1;
left– 和 right++ 是在“字符已经相等之后”执行的,也就是说：最后一次比较 是成功的,然后左右指针 又各自多走了一步,所以 最终得到的「回文长度」是 : right - left - 1


相关练习题1. LeetCode 5. 最长回文子串题意： 给你一个字符串 s，找到 s 中最长的回文子串。
2. LeetCode 680. 验证回文字符串 Ⅱ题意： 给定一个非空字符串 s ，最多删除一个字符。判断是否能成为回文字符串。
3. LeetCode 132. 分割回文串 II题意： 给你一个字符串 s，请你将 s 分割成一些子串，使每个子串都是回文串。返回符合要求的 最少分割次数 。

“秋天的光，落在旧京的屋檐上，也落在人的心里。”



  夜色在延伸，风拂过故都的屋瓦。  
  如果推理有情绪，那应当是秋天的温度。  
  郁达夫笔下的秋，是北国的，是孤独的，是一场无人破案的寂寞。



🍂 一、我喜北京的秋天我喜北京的秋天。最令人喜悦的，是那清、那静、那悲凉。秋天的颜色，不在浓艳，而在那浅淡的黄与灰里。清晨薄雾，傍晚凉风，枯叶在灰砖上低语，一切都那么寂寥、那么真切。
在南方，秋天只是个季节；在北国，它却是一种情绪，一种生命的姿态。

🌇 二、胡同里的风声那一条条深灰色的胡同，藏着老北京的灵魂。黄昏时分，炊烟与落日交织，远处传来一阵清脆的自行车铃声，便是秋的节拍。
有人说北京的秋冷，我却觉得它冷得有分寸。像一位旧友，不言不语，却让人心生安定。

🍁 三、落叶的推理故都的秋，是一首无声的诗。一阵风掠过，树叶在石阶上旋舞——那声音，如同旧琴拨弦。街角的银杏树披上金衣，枫叶燃烧在风里。行人脚下的叶，似在低语：

“别忘了这座城的温柔。”


💭 四、读后感郁达夫笔下的秋，不只是自然的描写，更是一种心境的投影。他看到了凋零之美，看到了孤独中的诗意。如今读来，仍能感受到那份淡淡的忧愁与温柔的宁静。


📎 原文作者：郁达夫（1934）📚 赏析与再创作：Fliex



